import{_ as e,W as a,X as t,Y as i}from"./framework-9a5142fa.js";const l={},p=i('<hr><h2 id="电脑黑屏" tabindex="-1"><a class="header-anchor" href="#电脑黑屏" aria-hidden="true">#</a> 电脑黑屏</h2><p>金手指问题。拿橡皮、卫生纸狠狠地擦，再狠狠地插上卡槽。</p><ul><li>我们擦的不狠，氧化膜掉不了。</li><li>两台主机上都以为内存条坏了，结果是内存条就没插紧………………</li><li>插槽，换着插。可能在a槽不好，b槽好，还不能说明是b槽坏了，然后另一条内存条在b槽也能用。</li></ul><p>键盘大小写的指示灯是个好东西，如果亮了，说明内存条没有问题。</p><p>显卡是必须插的，插主机上结果最后才知道没有核显………………</p><p>开机是有等待时间的…………</p><ul><li>开机后按了几下，以为键盘灯没亮，就寄了。结果再等10秒，魏哥按了一下就亮了。看来确实得频繁按、坚持按。</li><li>键盘的亮了后，过了好大一会，显示屏才亮。服了，合着本来早就好了。</li></ul><p>h低，b中，z高。低端主板可能没有主板指示灯。这款z490p，那个很艺术的灯条就是，哈哈哈哈，和b站视频演示的标准灯不一样，我还以为没有，高端主板太高端了。</p><p>注意用电安全。我们老是不关主机的电源开关和拔掉插头，需要注意。</p><h2 id="u盘格式-ntfs" tabindex="-1"><a class="header-anchor" href="#u盘格式-ntfs" aria-hidden="true">#</a> U盘格式：NTFS</h2><p>小容量（4G上限）的FAT32，大容量的NTFS。</p><p>不要考虑exFat。原因很简单：1、exFAT丢文件极其严重；2、exFAT 兼容性，尤其插手机、电视机；3、exFAT 要授权，比如插NAS。</p><p>NTFS影响寿命？确实，但没必要，坏的时候都该换新一代U盘了。</p>',14),r=[p];function n(c,s){return a(),t("div",null,r)}const _=e(l,[["render",n],["__file","硬件.html.vue"]]);export{_ as default};
